INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8b395beb-21e6-4907-9b49-39000d2456d9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Godot Scene Graph — Mastering Hierarchical Object Structure$escape$,
  $escape$Godot's scene graph is a hierarchical structure of nodes, where each node has a parent-child relationship with others. The Node2D or Node3D class serves as the base for all nodes, providing properties like position, rotation, and scale. When a node is added as a child to another, its transform is relative to its parent's transform. This allows for efficient management of complex scenes. Godot's built-in APIs, such as get_parent() and add_child(), simplify node manipulation. Understanding the scene graph is crucial for creating complex game worlds and levels.$escape$,
  $escape$var child_node = Node2D.new()
add_child(child_node)
child_node.position = Vector2(10, 20)
print(get_parent().name)$escape$,
  $escape$gdscript$escape$,
