INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '02172830-357f-4818-a18b-df02166b1568',
  '00000000-0000-0000-0000-000000000001',
  $escape$Godot Physics Optimization: Rigidbody, Colliders, and Layers$escape$,
  $escape$Godot's physics engine can be optimized by carefully configuring Rigidbody, Colliders, and Physics Layers. Rigidbody nodes provide collision detection and response, while Colliders define the shape of the object. Physics Layers allow for fine-grained control over collision interactions. To improve performance, use the `set_collision_layer` and `set_collision_mask` methods to filter out unnecessary collisions. Additionally, use triggers to detect collisions without affecting the physics simulation.$escape$,
  $escape$extends Rigidbody
func _ready():
    set_collision_layer(1)
    set_collision_mask(2)
    $CollisionShape.set_disabled(true)
    $CollisionShape.set_trigger(true)$escape$,
  $escape$gdscript$escape$,
