INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7c4e9ca5-42f3-474c-9835-a68d344a34c6',
  '00000000-0000-0000-0000-000000000001',
  $escape$Godot Input Handling — Simplifying Controller Support with Action Maps$escape$,
  $escape$Godot's input system provides a robust way to handle user input through action maps. Action maps allow you to abstract input actions from specific input devices, making it easier to support multiple controllers. You can create action maps using the Project Settings > Input Map tab. To handle input buffering, use the `Input.is_action_just_pressed()` and `Input.is_action_just_released()` functions. For more complex input handling, utilize the `InputEvent` class to capture and process raw input events.$escape$,
  $escape$func _process(delta):
    if Input.is_action_just_pressed('ui_accept'):
        print('UI Accept pressed')
    if Input.is_action_just_released('ui_cancel'):
        print('UI Cancel released')$escape$,
  $escape$gdscript$escape$,
