INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3c64ee9b-6d1b-4536-a6e9-c6ed73376898',
  '00000000-0000-0000-0000-000000000001',
  $escape$Godot UI Optimization: World-Space vs Screen-Space UI$escape$,
  $escape$Godot provides two primary ways to render UI elements: world-space and screen-space. World-space UI is rendered as part of the 3D scene, allowing for immersive and interactive experiences. Screen-space UI, on the other hand, is rendered on top of the 3D scene, ideal for HUD elements, menus, and other overlaying interfaces. To achieve this in Godot, use the `Control` node for screen-space UI and the `MeshInstance` node with a `CanvasLayer` for world-space UI. This approach enables efficient rendering and reduces performance overhead. Godot's `Camera` node also plays a crucial role in determining the rendering order and perspective of world-space UI elements.$escape$,
  $escape$var control = Control.new()
control.set_size(Vector2(100, 100))
add_child(control)
var camera = Camera.new()
add_child(camera)
var canvas_layer = CanvasLayer.new()
add_child(canvas_layer)$escape$,
  $escape$gdscript$escape$,
