INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '74db105c-fa1e-4d72-a828-d50c32a0c595',
  '00000000-0000-0000-0000-000000000001',
  $escape$Godot: Prototyping vs Production — When to Switch Scenes$escape$,
  $escape$Godot's scene system is ideal for prototyping, allowing for rapid testing and iteration. However, as projects grow, scene management becomes crucial. When prototyping, use the built-in SceneTree to manage nodes and scenes. For production, consider using a custom Scene Manager script to handle scene loading and unloading, reducing memory usage and improving performance. Use the `get_tree().change_scene()` function to switch between scenes. To optimize scene loading, use the `preload()` function to load scenes ahead of time.$escape$,
  $escape$func change_scene():
    var next_scene = preload("res://NextScene.tscn")
    get_tree().change_scene_to(next_scene)$escape$,
  $escape$gdscript$escape$,
