INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'af000531-45e1-4500-8df2-1172d3fddb3e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Godot Exporting: Creating Platform-Specific Builds$escape$,
  $escape$Godot's export system allows developers to create platform-specific builds for their games. The Export dialog in Godot provides options to customize the export process, including setting the export path, template, and debug mode. To create a platform-specific build, select the desired platform in the Export dialog and configure the export settings as needed. Godot supports exporting to various platforms, including Windows, macOS, Linux, Android, and iOS. The `ProjectSettings` class in GDScript provides access to project settings, including export settings. By using the `ProjectSettings` class, developers can automate the export process and create custom export scripts.$escape$,
  $escape$var export_config = ProjectSettings.get_setting('export/config');
export_config['platform'] = 'Windows';
ProjectSettings.set_setting('export/config', export_config);
OS.execute('godot', '--export', 'Windows', 'path/to/export');$escape$,
  $escape$gdscript$escape$,
